const input = $input.first().json;
const rawJobs = input.jobs || input.results || [];

function asText(value, fallback = 'Unknown') {
  const text = (value ?? '').toString().trim();
  return text || fallback;
}

function mapEmploymentType(value) {
  const source = asText(value, '').toLowerCase();
  if (source.includes('intern')) return 'Internship';
  if (source.includes('part')) return 'Part-time';
  return 'Full-time';
}

function mapExperience(text) {
  const source = asText(text, '').toLowerCase();
  if (source.includes('senior') || source.includes('lead') || source.includes('5+') || source.includes('6+')) return 'Mid';
  if (source.includes('junior') || source.includes('1+') || source.includes('2+')) return 'Junior';
  if (source.includes('intern') || source.includes('entry') || source.includes('fresher')) return 'Fresher';
  return 'Junior';
}

function mapDepartment(title) {
  const source = asText(title, '').toLowerCase();
  if (source.includes('data') || source.includes('ml') || source.includes('ai')) return 'Data';
  if (source.includes('devops') || source.includes('site reliability') || source.includes('sre')) return 'Operations';
  if (source.includes('analyst') || source.includes('product')) return 'Product';
  return 'Engineering';
}

function mapCategory(title, department) {
  const source = asText(title, '').toLowerCase();
  if (department === 'Data') return 'Analytics & AI';
  if (department === 'Operations') return 'Infrastructure';
  if (source.includes('analyst') || source.includes('product')) return 'Business & Strategy';
  return 'Software Engineering';
}

function mapWorkplaceType(candidate) {
  const source = asText(candidate, '').toLowerCase();
  if (source.includes('hybrid')) return 'Hybrid';
  if (source.includes('remote')) return 'Remote';
  return 'On-site';
}

function extractSkills(job) {
  const candidates = [
    job.tags,
    job.skills,
    job.keywords,
  ];

  for (const candidate of candidates) {
    if (Array.isArray(candidate) && candidate.length) {
      return candidate.map((x) => asText(x, '')).filter(Boolean).join(', ');
    }
    if (typeof candidate === 'string' && candidate.trim()) {
      return candidate.trim();
    }
  }

  return 'Communication, Problem Solving';
}

function toIsoDate(value) {
  const parsed = new Date(value || Date.now());
  if (Number.isNaN(parsed.getTime())) {
    return new Date().toISOString().slice(0, 10);
  }
  return parsed.toISOString().slice(0, 10);
}

function careerPageUrlFromApplyUrl(applyUrl) {
  if (!applyUrl) return '';
  try {
    const parsed = new URL(applyUrl);
    return `${parsed.origin}/careers`;
  } catch (error) {
    return '';
  }
}

const opportunities = rawJobs.map((job) => {
  const title = asText(job.title, 'Software Engineer');
  const company = asText(job.company_name || job.company || job.companyName, 'Unknown Company');
  const employmentType = mapEmploymentType(job.job_type || job.employment_type || job.type);
  const experienceLevel = mapExperience(job.candidate_required_location || title);
  const department = mapDepartment(title);
  const category = mapCategory(title, department);
  const location = asText(job.candidate_required_location || job.location, 'Remote');
  const workplaceType = mapWorkplaceType(location);
  const description = asText(job.description || job.job_description || job.body || '', 'No detailed description provided.');
  const applyUrl = asText(job.url || job.apply_url || job.apply_link || '', '');

  return {
    company_name: company,
    title,
    employment_type: employmentType,
    experience_level: experienceLevel,
    skills_required: extractSkills(job),
    department: department,
    category: category,
    location: location,
    workplace_type: workplaceType,
    posted_on: toIsoDate(job.publication_date || job.posted_on || job.created_at),
    career_page_url: careerPageUrlFromApplyUrl(applyUrl),
    apply_url: applyUrl,
    job_description: description
  };
});

const cleaned = opportunities.filter((o) => o.company_name && o.title && o.location && o.posted_on);

return [{ json: { opportunities: cleaned } }];
